class User:
    def __init__(self, name):
        self.name = name

    def greet(self):
        print(f"Привет, {self.name}!")

user = User("Анна")
user.greet()

class Counter:
    def __init__(self):
        self.value = 0

    def increase(self):
        self.value += 1

counter = Counter()
counter.increase()
print(counter.value)

class BankAccount:
    def __init__(self):
        self.balance = 0

    def deposit(self, amount):
        self.balance += amount

account = BankAccount()
account.deposit(500)
print(account.balance)

